import{_ as r,o as t,c as o,a2 as i}from"./chunks/framework.BwNZcjNV.js";const c=JSON.parse('{"title":"게시판","description":"","frontmatter":{},"headers":[],"relativePath":"work-manage/forum.md","filePath":"work-manage/forum.md","lastUpdated":1784824392000}'),l={name:"work-manage/forum.md"};function e(n,a,s,d,h,u){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="게시판" tabindex="-1">게시판 <a class="header-anchor" href="#게시판" aria-label="Permalink to &quot;게시판&quot;">​</a></h1><p>프로젝트 구성원 간의 자유로운 의견 교환과 지식 공유를 위한 <strong>게시판</strong> 페이지에 대한 사용자 가이드입니다.</p><h2 id="_1-화면-개요" tabindex="-1">1. 화면 개요 <a class="header-anchor" href="#_1-화면-개요" aria-label="Permalink to &quot;1. 화면 개요&quot;">​</a></h2><p>게시판 화면은 프로젝트별로 여러 개의 게시판을 생성하여 운영할 수 있는 다중 게시판 시스템을 제공합니다. 질문 답변, 자유 게시판, 기술 공유 등 목적에 맞는 게시판을 통해 효율적인 커뮤니케이션을 지원합니다.</p><h2 id="_2-주요-기능-안내" tabindex="-1">2. 주요 기능 안내 <a class="header-anchor" href="#_2-주요-기능-안내" aria-label="Permalink to &quot;2. 주요 기능 안내&quot;">​</a></h2><h3 id="📋-게시판-인덱스-및-목록" tabindex="-1">📋 게시판 인덱스 및 목록 <a class="header-anchor" href="#📋-게시판-인덱스-및-목록" aria-label="Permalink to &quot;📋 게시판 인덱스 및 목록&quot;">​</a></h3><ul><li><strong>게시판 선택</strong>: 프로젝트 내에 생성된 여러 게시판 목록을 확인하고 원하는 게시판으로 진입합니다.</li><li><strong>게시물 목록</strong>: 선택한 게시판에 등록된 글들을 최신순으로 확인하며, 제목, 작성자, 작성일, 조회수 등의 정보를 제공합니다.</li><li><strong>페이지네이션</strong>: 게시물이 많을 경우 하단의 페이지 번호를 통해 과거 게시물을 조회할 수 있습니다.</li></ul><h3 id="✍️-게시물-작성-및-관리" tabindex="-1">✍️ 게시물 작성 및 관리 <a class="header-anchor" href="#✍️-게시물-작성-및-관리" aria-label="Permalink to &quot;✍️ 게시물 작성 및 관리&quot;">​</a></h3><ul><li><strong>게시물 등록</strong>: 제목과 본문을 작성하고, 필요시 카테고리를 선택하여 글을 게시합니다.</li><li><strong>편집 및 삭제</strong>: 본인이 작성한 글은 언제든지 수정하거나 삭제할 수 있습니다. 삭제 전에는 확인 모달을 통해 실수로 인한 데이터 손실을 방지합니다.</li><li><strong>조회수 트래킹</strong>: 게시물 열람 시 조회수가 자동으로 증가하여 관심도를 파악할 수 있습니다.</li></ul><h3 id="💬-소통-및-반응-기능" tabindex="-1">💬 소통 및 반응 기능 <a class="header-anchor" href="#💬-소통-및-반응-기능" aria-label="Permalink to &quot;💬 소통 및 반응 기능&quot;">​</a></h3><p>상세 보기 화면에서 다른 사용자의 글에 대해 다양한 방식으로 반응할 수 있습니다.</p><ul><li><strong>댓글 작성</strong>: 게시물 하단에 의견을 남겨 실시간으로 소통할 수 있습니다.</li><li><strong>추천 (Like)</strong>: 유익한 정보나 공감되는 글에 대해 추천 의사를 표시합니다.</li><li><strong>신고 (Blame)</strong>: 부적절한 게시물을 관리자에게 알릴 수 있습니다.</li></ul><h3 id="🛠️-게시판-관리-사이드바" tabindex="-1">🛠️ 게시판 관리 (사이드바) <a class="header-anchor" href="#🛠️-게시판-관리-사이드바" aria-label="Permalink to &quot;🛠️ 게시판 관리 (사이드바)&quot;">​</a></h3><p>우측 사이드바를 통해 게시판 관련 부가 기능을 빠르게 이용할 수 있습니다.</p><ul><li><strong>프로젝트 개요</strong> (<i class="mdi mdi-view-dashboard-outline"></i>): 현재 프로젝트의 전체 현황 페이지로 이동합니다.</li><li><strong>게시판 설정</strong> (<i class="mdi mdi-cog-outline"></i>): (관리자 전용) 게시판의 이름, 설명, 카테고리 등을 구성합니다.</li><li><strong>휴지통</strong> (<i class="mdi mdi-trash-can-outline"></i>): 삭제된 게시물을 확인하거나 복구할 수 있는 공간입니다.</li></ul><h2 id="_3-이용-팁" tabindex="-1">3. 이용 팁 <a class="header-anchor" href="#_3-이용-팁" aria-label="Permalink to &quot;3. 이용 팁&quot;">​</a></h2><ul><li><strong>카테고리 활용</strong>: 게시판 설정에서 카테고리를 잘 정의해두면, 방대한 게시물 사이에서 원하는 주제의 글을 더 쉽게 필터링할 수 있습니다.</li><li><strong>지식 자산화</strong>: 단순한 질의응답도 게시판에 남겨두면 나중에 참여하는 팀원들에게 훌륭한 업무 가이드가 됩니다.</li><li><strong>상세 보기 브레드크럼</strong>: 게시물 상세 화면 상단의 경로 링크(예: 게시판 » 목록)를 활용해 목록으로 빠르게 복귀할 수 있습니다.</li></ul>',17)])])}const m=r(l,[["render",e]]);export{c as __pageData,m as default};
